Hier ist die Spezifikation für das "Clean Action Bar"-Design.

### Spezifikation & Design

**1. Konzept: Reine Werkzeugleiste**
Wir entfernen alle informativen Texte (Titel & Zähler) aus dem Header. Der Header wird zu einer funktionalen "Toolbar", die nur noch Steuerelemente enthält.

**2. Layout-Änderung (Split-Alignment):**
Um den gewonnenen Platz optimal zu nutzen und Fehlklicks zu vermeiden, trennen wir die Funktionen räumlich:
*   **Links (View Control):** Der "Alle Einklappen/Ausklappen"-Button wandert ganz nach links. Er steht dort allein und ist sehr leicht zu treffen.
*   **Rechts (Primary Action):** Der "Neuer Eintrag"-Button bleibt rechts.

**3. Quality Gates:**
*   **Gate 1 (Ergonomie):** Durch die Trennung (Links/Rechts) wird verhindert, dass man versehentlich auf "Einklappen" drückt, wenn man eigentlich "Hinzufügen" will.
*   **Gate 2 (Minimalismus):** Die Leiste nimmt visuell weniger kognitive Last auf, da kein Text mehr gelesen werden muss.
*   **Gate 3 (Feedback):** Da der Zähler fehlt, ist das visuelle Feedback beim Einklappen (Animation der Liste) umso wichtiger (bereits implementiert).

Hier sind die Änderungen:

# Updated files:

## components/Dashboard.tsx

Entfernt Titel und Zähler. Positioniert den "Einklappen"-Button links und den "Hinzufügen"-Button rechts für eine klare Toolbar-Struktur.

```tsx
import React, { useState, useMemo } from 'react';
import { FoodItem, GroceryCategory } from '../types';
import { FoodItemList } from './FoodItemList';
import { useTranslation } from '../i18n/index';
import { PlusCircleIcon, SparklesIcon, ArrowsPointingInIcon, ArrowsPointingOutIcon } from './Icons';

interface DashboardProps {
  items: FoodItem[];
  isLoading?: boolean;
  onAddNew: () => void;
  onDelete: (id: string) => void;
  onEdit: (id: string) => void;
  onViewDetails: (item: FoodItem) => void;
  onAddToShoppingList: (item: FoodItem) => void;
  shoppingListFoodIds?: Set<string>;
  isFiltering?: boolean;
}

export const Dashboard: React.FC<DashboardProps> = ({ 
  items, 
  isLoading, 
  onAddNew, 
  onDelete, 
  onEdit, 
  onViewDetails, 
  onAddToShoppingList, 
  shoppingListFoodIds,
  isFiltering
}) => {
  const { t } = useTranslation();
  const [collapsedCategories, setCollapsedCategories] = useState<Set<string>>(new Set());

  // Logic to determine all categories currently present
  const allCategories = useMemo(() => {
      const cats = new Set<string>();
      items.forEach(item => cats.add(item.category || 'other'));
      return Array.from(cats);
  }, [items]);

  const isAllCollapsed = allCategories.length > 0 && collapsedCategories.size === allCategories.length;

  const toggleCategory = (category: string) => {
      setCollapsedCategories(prev => {
          const newSet = new Set(prev);
          if (newSet.has(category)) {
              newSet.delete(category);
          } else {
              newSet.add(category);
          }
          return newSet;
      });
  };

  const toggleAll = () => {
      if (isAllCollapsed) {
          setCollapsedCategories(new Set()); // Expand all
      } else {
          setCollapsedCategories(new Set(allCategories)); // Collapse all
      }
  };

  if (isLoading) {
      return (
        <div className="space-y-8 pt-6">
            <FoodItemList 
                items={[]} 
                isLoading={true} 
                onDelete={onDelete} 
                onEdit={onEdit} 
                onViewDetails={onViewDetails} 
                onAddToShoppingList={onAddToShoppingList}
                collapsedCategories={collapsedCategories}
                onToggleCategory={toggleCategory}
            />
        </div>
      );
  }

  // Show "Onboarding" empty state only if we have NO items and are NOT filtering.
  if (items.length === 0 && !isFiltering) {
    return (
      <div className="text-center py-16 px-4 animate-fade-in flex flex-col items-center">
        <div className="bg-gradient-to-br from-indigo-100 to-purple-100 dark:from-indigo-900/30 dark:to-purple-900/30 w-32 h-32 rounded-full flex items-center justify-center mb-8 shadow-inner">
            <SparklesIcon className="w-16 h-16 text-indigo-500 dark:text-indigo-400 opacity-80" />
        </div>
        <h2 className="text-3xl font-extrabold text-gray-900 dark:text-gray-100 mb-4">{t('dashboard.empty.title')}</h2>
        <p className="text-gray-600 dark:text-gray-400 mb-10 max-w-md mx-auto leading-relaxed text-lg">{t('dashboard.empty.description')}</p>

        {/* Internal Add Button for Empty State */}
        <button
            onClick={onAddNew}
            className="bg-indigo-600 hover:bg-indigo-700 text-white font-bold py-4 px-10 rounded-full shadow-xl transition-all transform hover:scale-105 hover:shadow-2xl flex items-center justify-center gap-3"
        >
            <PlusCircleIcon className="w-6 h-6" />
            <span className="text-lg">{t('form.addNewButton')}</span>
        </button>
      </div>
    );
  }

  return (
    <div className="space-y-4 pb-24">
      {/* Clean Toolbar Header */}
      <div className="flex justify-between items-center px-1 py-2 sticky top-[72px] z-10 bg-gray-100/95 dark:bg-gray-900/95 backdrop-blur-sm -mx-2 sm:mx-0 sm:rounded-lg border-b border-gray-200/50 dark:border-gray-800/50">

         {/* Left: View Control (Collapse/Expand) */}
         <div className="pl-1">
             {items.length > 0 && (
                 <button 
                    onClick={toggleAll}
                    className="p-2.5 rounded-full text-gray-600 hover:text-indigo-600 dark:text-gray-400 dark:hover:text-indigo-400 bg-white dark:bg-gray-800 shadow-sm border border-gray-200 dark:border-gray-700 hover:shadow-md transition-all active:scale-95"
                    title={isAllCollapsed ? "Alle ausklappen" : "Alle einklappen"}
                    aria-label={isAllCollapsed ? "Expand all categories" : "Collapse all categories"}
                 >
                    {isAllCollapsed ? <ArrowsPointingOutIcon className="w-5 h-5" /> : <ArrowsPointingInIcon className="w-5 h-5" />}
                 </button>
             )}
         </div>

         {/* Right: Primary Action (Add New) */}
         <div className="pr-1">
             <button
                onClick={onAddNew}
                className="flex items-center gap-2 bg-indigo-600 hover:bg-indigo-700 text-white font-semibold py-2 px-4 rounded-full shadow-md transition-all active:scale-95 hover:shadow-lg"
             >
                <PlusCircleIcon className="w-5 h-5" />
                <span className="text-sm">{t('form.addNewButton')}</span>
             </button>
         </div>
      </div>

      <FoodItemList 
        items={items} 
        isLoading={false}
        onDelete={onDelete}
        onEdit={onEdit}
        onViewDetails={onViewDetails}
        onAddToShoppingList={onAddToShoppingList}
        shoppingListFoodIds={shoppingListFoodIds}
        collapsedCategories={collapsedCategories}
        onToggleCategory={toggleCategory}
      />
    </div>
  );
};
